using Microsoft.AspNetCore.Mvc;
using System.IO;
namespace FileUploaderApp.Controllers
{    
    [Route("api/[controller]")] // api/{filename} -> this is the route template for our controller action method 
                                           (example: "http://localhost:5001/api/file?filename=test")
                                  
   public class FileController : ControllerBase     {       
       [HttpGet("{filename}")] // This attribute binds to http GET requests on the filename route template.         
                               /*  Here we are returning a file from our 'uploaded' directory with its content type set automatically by ASP .NET Core */    public IActionResult GetFile(string filename)     {        if (System.IO.File.Exists("~/Uploads/" + filename))      return PhysicalFile(filename, "application/octet-stream");       else         //return 404 not found status code and a message
                                           {"The file does not exist"};    }     }}